import{_ as r,G as l,c as n,o as e,j as t,J as s,a6 as a,a as g}from"./chunks/framework.D3uGTwuV.js";const _=JSON.parse('{"title":"PicGo的使用方法","description":"","frontmatter":{},"headers":[],"relativePath":"技巧/PicGo的使用方法.md","filePath":"技巧/PicGo的使用方法.md","lastUpdated":1775109753000}'),c={name:"技巧/PicGo的使用方法.md"};function d(p,o,u,h,P,b){const i=l("ArticleMetadata");return e(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1775109753000"},[o[0]||(o[0]=t("h1",{id:"picgo的使用方法",tabindex:"-1"},[g("PicGo的使用方法 "),t("a",{class:"header-anchor",href:"#picgo的使用方法","aria-label":"Permalink to “PicGo的使用方法”"},"​")],-1)),s(i),o[1]||(o[1]=a('<h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to “使用方法”">​</a></h2><ol><li><strong>安装</strong><ul><li><strong>Windows</strong>：从官网下载 Windows 版本的安装包，然后按照提示进行安装 <ul><li><a href="https://picgo.github.io/PicGo-Doc/zh/guide/#%E4%B8%8B%E8%BD%BD%E5%AE%89%E8%A3%85" target="_blank" rel="noreferrer">https://picgo.github.io/PicGo-Doc/zh/guide/#%E4%B8%8B%E8%BD%BD%E5%AE%89%E8%A3%85</a></li><li>然后按照提示进行安装。</li></ul></li><li>或者通过蓝奏云下载 <ul><li>下载链接：<a href="https://starryweb.lanzout.com/i2ymP2nvepub" target="_blank" rel="noreferrer">https://starryweb.lanzout.com/i2ymP2nvepub</a><br> 密码: <code>ehvi</code></li></ul></li></ul></li><li><strong>打开</strong><ul><li>双击打开，注意如果<strong>窗口</strong>没有直接出现，要点开托盘再点 picgo 就行了 <img src="https://cdn.nlark.com/yuque/0/2025/png/42939896/1739617583077-d5fee1e8-ec37-4077-8ba4-101784602ee0.png" alt=""></li></ul></li><li><strong>配置</strong><ul><li><strong>配置环境</strong>：如果使用的是 Windows 系统，可能需要配置环境变量，以便在命令行中直接使用 PicGo 命令。</li><li><strong>配置图床</strong>：打开 PicGo 软件，在设置中选择“图床设置”，根据自己的需求选择合适的图床服务，如阿里云 OSS、腾讯云 COS、GitHub 等。可以参照本项目已有的配置： <img src="https://cdn.nlark.com/yuque/0/2025/png/42939896/1739617698184-a24008af-5fe2-4efe-ba57-478fca9578da.png" alt=""></li><li><strong>配置：</strong><ul><li><strong>COS版本:</strong> v5</li><li><strong>设定SecretId:</strong> <code>AKIDUqzv...AHHC6rRoz</code></li><li><strong>设定SecretKey:</strong> <code>3ua3MRN...obQ8f1A8vW</code><br> ⚠️ <strong>千万不要告诉别人不然可能会被 DDoS 攻击</strong></li><li><strong>设定Bucket:</strong> starrywebpic-1324480062</li><li><strong>设定AppId:</strong> 1324480062</li><li><strong>设定存储区域:</strong> ap-guangzhou</li><li>**设定存储路径: **test/</li><li><strong>设定自定义域名:</strong> 不填</li><li><strong>设定网址后缀:</strong> 不填</li></ul></li></ul></li><li><strong>使用</strong><ul><li><strong>上传图片</strong>：可以通过多种方式上传图片，如直接将图片拖拽到 PicGo 的界面中，或者使用快捷键<code>Ctrl+U</code>（Windows）或<code>Command+U</code>（Mac）快速上传剪贴板中的图片。 <img src="https://cdn.nlark.com/yuque/0/2025/png/42939896/1739618113306-6bb32edc-738d-4d88-92b4-7357162722ca.png" alt=""></li><li><strong>查看上传记录</strong>：在 PicGo 的主界面中，可以查看已上传的图片记录，方便管理和查找。</li><li><strong>删除图片</strong>：如果需要删除已上传的图片，可以在对应的图床服务中进行操作，或者使用 PicGo 提供的删除功能。</li><li><strong>图片压缩</strong>：为了节省存储空间和提高上传速度，可以在 PicGo 的设置中启用图片压缩功能，并根据需要调整压缩参数。</li><li><strong>复制链接：</strong>在上传区域点击<strong>URL</strong><img src="https://cdn.nlark.com/yuque/0/2025/png/42939896/1739618171359-01fb9783-d718-4a9a-ac77-25bf7fc8b927.png" alt="">然后找到相册想要复制的图片后复制就可以了</li></ul></li></ol><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to “优势”">​</a></h2><ol><li><strong>支持多种图床</strong>：PicGo 支持包括但不限于 SM.MS、腾讯云 COS、阿里云 OSS、GitHub、七牛云等在内的多种图床服务，用户可以根据自己的需求选择合适的图床。</li><li><strong>操作简便</strong>：PicGo 的界面简洁直观，操作方便，支持拖拽和快捷键上传图片，极大地提高了用户的上传效率。</li><li><strong>插件系统</strong>：PicGo 拥有一个插件系统，允许用户安装额外的插件来扩展其功能，例如支持更多图床、添加图片压缩等。</li><li><strong>跨平台</strong>：PicGo 支持多个操作系统，包括 Windows、macOS 和 Linux，用户可以在不同的设备上使用 PicGo。</li><li><strong>免费开源</strong>：PicGo 是一款免费的开源软件，用户可以自由使用和修改其源代码。</li></ol><h2 id="劣势" tabindex="-1">劣势 <a class="header-anchor" href="#劣势" aria-label="Permalink to “劣势”">​</a></h2><ol><li><strong>依赖第三方存储服务</strong>：PicGo 依赖于第三方图床服务，如果图床服务不可用，可能导致图片无法访问，影响笔记的完整性。</li><li><strong>存在隐私风险</strong>：将图片上传到第三方图床可能存在隐私泄露的风险，用户需要谨慎选择图床服务，并注意保护个人隐私。</li><li><strong>离线状态下失效</strong>：在离线状态下，PicGo 无法上传图片，笔记内容可能不完整，影响工作效率。</li><li><strong>流量费用</strong>：如果使用付费的图床服务，如腾讯云 COS、阿里云 OSS 等，可能会产生流量费用，用户需要根据自己的需求和预算选择合适的图床服务。</li><li><strong>配置复杂</strong>：对于一些新手用户来说，配置 PicGo 可能会比较复杂，需要一定的技术基础。</li></ol>',6))])}const f=r(c,[["render",d]]);export{_ as __pageData,f as default};
